const metrics = {
  clk: {length_mm: 49, skew_ps: 32, margin_ps: 64},
  data0: {length_mm: 62, skew_ps: 38, margin_ps: 48},
  thermal: {loss_current_a: 4.4, drop_v: 1.2, theta_ja_c_per_w: 35, ambient_c: 50},
};
metrics.clk.headroom_ps = metrics.clk.margin_ps - metrics.clk.skew_ps;
metrics.data0.headroom_ps = metrics.data0.margin_ps - metrics.data0.skew_ps;
metrics.clk.utilization = metrics.clk.skew_ps / metrics.clk.margin_ps;
metrics.data0.utilization = metrics.data0.skew_ps / metrics.data0.margin_ps;
metrics.thermal.power_w = metrics.thermal.loss_current_a * metrics.thermal.drop_v;
metrics.thermal.delta_t_c = metrics.thermal.power_w * metrics.thermal.theta_ja_c_per_w;
metrics.thermal.estimated_tj_c = metrics.thermal.ambient_c + metrics.thermal.delta_t_c;
console.log(JSON.stringify(metrics, null, 2));
NODE"}

